// Old style — completion handlers
func loadUser(id: String, completion: @escaping (Result<User, Error>) -> Void) { /* ... */ }

// New style — async/await
func loadUser(id: String) async throws -> User {
  let url = URL(string: "https://api/users/\(id)")!
  let (data, _) = try await URLSession.shared.data(from: url)
  return try JSONDecoder().decode(User.self, from: data)
}

// Sequencing — looks synchronous
func loadProfile() async throws -> Profile {
  let user = try await loadUser(id: "42")
  let posts = try await loadPosts(for: user.id)
  let avatar = try await loadAvatar(for: user.id)
  return Profile(user: user, posts: posts, avatar: avatar)
}

// Calling async from sync context — Task entry
func viewDidAppear() {
  Task {
    do {
      let profile = try await loadProfile()
      await MainActor.run { self.show(profile) }
    } catch {
      await MainActor.run { self.showError(error) }
    }
  }
}

// Bridge legacy callbacks → async via withCheckedContinuation
func loadUser(id: String) async throws -> User {
  try await withCheckedThrowingContinuation { cont in
    legacy.loadUser(id: id) { result in cont.resume(with: result) }
  }
}

// Concurrent with async let
func loadDashboard() async throws -> Dashboard {
  async let posts = api.posts()
  async let friends = api.friends()
  async let news = api.news()
  // Three requests fly in parallel; await collects all (all-or-throw)
  return try await Dashboard(posts: posts, friends: friends, news: news)
}

// Dynamic fan-out via TaskGroup
func loadAvatars(_ ids: [String]) async throws -> [String: UIImage] {
  try await withThrowingTaskGroup(of: (String, UIImage).self) { group in
    for id in ids {
      group.addTask { (id, try await api.avatar(id: id)) }
    }
    var result: [String: UIImage] = [:]
    for try await (id, image) in group {
      result[id] = image
    }
    return result
  }
}

// Cancellation propagation
func search(_ q: String) async throws -> [Result] {
  // If parent task is cancelled, this throws CancellationError
  try Task.checkCancellation()
  return try await api.search(q)
}

// Manage a Task as state in a view model
class SearchVM {
  private var task: Task<Void, Never>?
  func search(_ q: String) {
    task?.cancel()
    task = Task { [weak self] in
      do {
        let r = try await api.search(q)
        if Task.isCancelled { return }
        await MainActor.run { self?.results = r }
      } catch {}
    }
  }
}

actor Counter {
  private var value: Int = 0
  func increment() { value += 1 }
  func current() -> Int { value }
  nonisolated func describe() -> String { "Counter" } // doesn't touch state
}

let c = Counter()
Task { await c.increment() }
Task { print(await c.current()) }
