// MainActor — pin a class to the main thread
@MainActor
class HomeViewModel: ObservableObject {
  @Published var items: [Item] = []
  func reload() async {
    let next = try? await api.items()    // off-main while suspended
    self.items = next ?? []              // back on main automatically
  }
}

