// Reentrancy gotcha — do not assume state across awaits
actor Cache {
  private var value: Int?
  func load() async -> Int {
    if let v = value { return v }
    let fetched = await network.fetch() // ⚠️ another task could run here
    if let v = value { return v }        // re-check after suspension
    value = fetched
    return fetched
  }
}

