// Bridge a delegate API into AsyncStream
class LocationManager: NSObject, CLLocationManagerDelegate {
  var stream: AsyncStream<CLLocation>!
  private var continuation: AsyncStream<CLLocation>.Continuation!
  let manager = CLLocationManager()
  override init() {
    super.init()
    manager.delegate = self
    let s = AsyncStream<CLLocation> { continuation in
      self.continuation = continuation
      continuation.onTermination = { @Sendable _ in self.manager.stopUpdatingLocation() }
    }
    self.stream = s
  }
  func locationManager(_ m: CLLocationManager, didUpdateLocations locs: [CLLocation]) {
    for l in locs { continuation.yield(l) }
  }
}

// Consumer
Task {
  for await loc in LocationManager().stream {
    update(loc)
  }
}

