// Sendable struct — automatic
struct User: Sendable { let id: Int; let name: String }

// Final class with let-only properties — automatic
final class Config: Sendable {
  let apiKey: String
  init(apiKey: String) { self.apiKey = apiKey }
}

// Mutable class — opt-out, justify with locking
final class Counter: @unchecked Sendable {
  private let lock = NSLock()
  private var _value = 0
  var value: Int { lock.lock(); defer { lock.unlock() }; return _value }
  func increment() { lock.lock(); defer { lock.unlock() }; _value += 1 }
}

// Sendable closure — required by Task.detached et al.
func spawn(_ work: @Sendable @escaping () -> Void) {
  Task.detached { work() }
}

