// Generic constraint
func parallelMap<T: Sendable, U: Sendable>(_ xs: [T], _ f: @Sendable (T) async -> U) async -> [U] {
  await withTaskGroup(of: (Int, U).self) { group in
    for (i, x) in xs.enumerated() {
      group.addTask { (i, await f(x)) }
    }
    var result = Array<U?>(repeating: nil, count: xs.count)
    for await (i, u) in group { result[i] = u }
    return result.compactMap { $0 }
  }
}

class SearchVM: ObservableObject {
  @Published var results: [Result] = []
  private var task: Task<Void, Never>?

  func update(query: String) {
    task?.cancel()
    task = Task { [weak self] in
      // Built-in: sleep honors cancellation
      try? await Task.sleep(for: .milliseconds(300)) // debounce
      guard !Task.isCancelled else { return }

      do {
        let r = try await api.search(query) // URLSession respects cancel
        try Task.checkCancellation()
        await MainActor.run { self?.results = r }
      } catch is CancellationError {
        // expected — newer keystroke won the race
      } catch {
        await MainActor.run { self?.show(error) }
      }
    }
  }

  deinit { task?.cancel() }
}

// Long-running work with cancellation hooks
func download(url: URL) async throws -> Data {
  let session = URLSession(configuration: .default)
  let task = session.dataTask(with: url)
  return try await withTaskCancellationHandler {
    try await withCheckedThrowingContinuation { cont in
      task.resume()
      // wire up completion to cont…
    }
  } onCancel: {
    task.cancel() // synchronous — must be Sendable
  }
}

